cat >> /root/.openclaw/workspace/persona_search_demo.html << 'HTMLEOF'

  // 如果已有搜索结果，重新渲染
  if (currentKeyword && document.getElementById('productsContainer').querySelector('.product-card')) {
    doSearch();
  }
}

// ===================== 加载 Persona 标签（调用真实接口） =====================
async function loadPersonaLabels(idx) {
  if (personaLabels[idx]) {
    renderProfile(idx);
    return;
  }

  const user = USERS[idx];
  document.getElementById('profileContent').innerHTML = '<div class="profile-loading">🔄 从 Persona 接口获取中...</div>';
  document.getElementById('profileSource').textContent = '';

  try {
    // 并发搜索该用户的多个维度标签
    const queries = user.persona.searchQueries;
    const results = await Promise.all(
      queries.map(q =>
        fetch(`/api/v2/ai/rag/dutvs/assets/searchAll?query=${encodeURIComponent(q)}&assetTypes=label&pageSize=3&idType=1`, {
          credentials: 'include'
        }).then(r => r.json()).then(d => ({ query: q, labels: d.data || [] }))
      )
    );

    // 整理标签分组
    const labelGroups = [];
    results.forEach(({ query, labels }) => {
      if (labels.length > 0) {
        labelGroups.push({
          title: query,
          labels: labels.slice(0, 3).map(l => ({
            id: l.id,
            name: l.assetName,
            similarity: l.similarity
          }))
        });
      }
    });

    personaLabels[idx] = labelGroups;
    document.getElementById('profileSource').textContent = '· Persona 真实接口';
    renderProfile(idx);

  } catch(e) {
    document.getElementById('profileContent').innerHTML = '<div class="profile-loading" style="color:#f56">接口请求失败，请检查登录状态</div>';
  }
}

// ===================== 渲染用户画像 =====================
function renderProfile(idx) {
  const user = USERS[idx];
  const groups = personaLabels[idx] || [];
  const typeClasses = ['preference', 'behavior', 'sensitivity'];

  let html = '';
  groups.forEach((group, gi) => {
    html += `<div class="label-group">
      <div class="label-group-title">🏷️ ${group.title}</div>
      <div class="label-tags">
        ${group.labels.map(l => `<span class="label-tag ${typeClasses[gi] || ''}" title="ID:${l.id} 相似度:${(l.similarity*100).toFixed(0)}%">${l.name}</span>`).join('')}
      </div>
    </div>`;
  });

  if (!html) html = '<div class="profile-loading">暂无标签数据</div>';
  document.getElementById('profileContent').innerHTML = html;
}

// ===================== 搜索主逻辑 =====================
function quickSearch(keyword) {
  document.getElementById('searchInput').value = keyword;
  doSearch();
}

function doSearch() {
  const keyword = document.getElementById('searchInput').value.trim();
  if (!keyword) return;

  currentKeyword = keyword;
  const user = USERS[currentUserIdx];
  const container = document.getElementById('productsContainer');
  const insight = document.getElementById('searchInsight');

  // 过滤匹配关键词的商品
  const matched = PRODUCTS.filter(p =>
    p.keywords.some(k => k.includes(keyword) || keyword.includes(k)) ||
    p.name.includes(keyword) ||
    p.categories.some(c => c.includes(keyword))
  );

  if (matched.length === 0) {
    container.innerHTML = `<div class="empty-state"><div class="emoji">😅</div><p>没有找到"${keyword}"相关商品</p></div>`;
    insight.className = 'search-insight';
    document.getElementById('compareBtn').style.display = 'none';
    document.getElementById('resultsCount').textContent = '';
    return;
  }

  // 个性化评分（基于画像权重）
  const scored = matched.map(p => {
    let score = 1.0;
    const w = user.persona.weights;

    // 价格权重
    if (w.price && p.tags.price) score *= (w.price[p.tags.price] || 1.0);
    // 健康权重
    if (w.health && p.tags.health) score *= (w.health[p.tags.health] || 1.0);
    // 品质权重
    if (w.quality && p.tags.quality) score *= (w.quality[p.tags.quality] || 1.0);
    // 品类加成
    const bonus = user.persona.categoryBonus || {};
    p.categories.forEach(c => {
      if (bonus[c]) score *= bonus[c];
    });
    p.keywords.forEach(k => {
      if (bonus[k]) score *= bonus[k];
    });

    // 基础销量加成（轻微）
    score *= (1 + Math.log10(p.sales + 1) * 0.05);

    return { ...p, score };
  }).sort((a, b) => b.score - a.score);

  // 展示搜索洞察
  const topLabel = scored[0];
  const whyText = getRecommendReason(scored[0], user);
  insight.innerHTML = `🎯 基于 <strong>${user.name}</strong> 的画像标签，为她个性化排序了 <strong>${scored.length}</strong> 件商品 · 首推：<strong>${topLabel.name}</strong>（${whyText}）`;
  insight.className = 'search-insight show';

  // 渲染商品卡片
  document.getElementById('resultsCount').textContent = `共 ${scored.length} 件商品`;
  document.getElementById('compareBtn').style.display = 'block';

  container.innerHTML = `<div class="products-grid">
    ${scored.map((p, i) => renderProductCard(p, i, user)).join('')}
  </div>`;
}

function getRecommendReason(product, user) {
  const reasons = [];
  if (product.tags.health === '健康' && user.persona.weights.health?.['健康'] > 1.5) reasons.push('健康偏好匹配');
  if (product.tags.price === '低价' && user.persona.weights.price?.['低价'] > 2.0) reasons.push('超值优惠');
  if (product.tags.quality === '精品' && user.persona.weights.quality?.['精品'] > 1.5) reasons.push('品质优先');
  if (product.categories.some(c => (user.persona.categoryBonus?.[c] || 0) > 1.5)) reasons.push('品类偏好');
  return reasons.length ? reasons.join(' · ') : '综合评分最高';
}

function renderProductCard(product, rank, user) {
  const reason = getRecommendReason(product, user);
  const rankBadge = rank < 3 ? `<div class="rank-badge rank-${rank+1}">${rank+1}</div>` : '';
  const recBadge = rank < 3 ? `<div class="recommend-badge">✨ ${reason}</div>` : '';

  return `<div class="product-card">
    ${recBadge}
    ${rankBadge}
    <div class="product-img">${product.emoji}</div>
    <div class="product-body">
      <div class="product-name">${product.name}</div>
      <div class="product-shop">${product.shop}</div>
      <div class="product-bottom">
        <div>
          <div class="product-price"><span>¥</span>${product.price}</div>
          <div class="product-sales">月售 ${product.sales.toLocaleString()}</div>
        </div>
        <div class="product-rating">⭐ ${product.rating}</div>
      </div>
    </div>
  </div>`;
}

// ===================== 对比面板 =====================
function toggleCompare() {
  compareVisible = !compareVisible;
  const panel = document.getElementById('comparePanel');
  panel.classList.toggle('show', compareVisible);
  document.getElementById('compareBtn').textContent = compareVisible ? '收起对比 ↑' : '对比不同用户结果 →';

  if (compareVisible) renderCompare();
}

function renderCompare() {
  const keyword = currentKeyword;
  const grid = document.getElementById('compareGrid');

  const allResults = USERS.map((user, idx) => {
    const matched = PRODUCTS.filter(p =>
      p.keywords.some(k => k.includes(keyword) || keyword.includes(k)) ||
      p.name.includes(keyword) ||
      p.categories.some(c => c.includes(keyword))
    );
    const scored = matched.map(p => {
      let score = 1.0;
      const w = user.persona.weights;
      if (w.price && p.tags.price) score *= (w.price[p.tags.price] || 1.0);
      if (w.health && p.tags.health) score *= (w.health[p.tags.health] || 1.0);
      if (w.quality && p.tags.quality) score *= (w.quality[p.tags.quality] || 1.0);
      const bonus = user.persona.categoryBonus || {};
      p.categories.forEach(c => { if (bonus[c]) score *= bonus[c]; });
      p.keywords.forEach(k => { if (bonus[k]) score *= bonus[k]; });
      score *= (1 + Math.log10(p.sales + 1) * 0.05);
      return { ...p, score };
    }).sort((a, b) => b.score - a.score);
    return { user, results: scored };
  });

  grid.innerHTML = allResults.map(({ user, results }) => `
    <div class="compare-col">
      <h4>${user.emoji} ${user.name}（${user.desc}）的排序</h4>
      ${results.slice(0, 5).map((p, i) => `
        <div class="compare-item">
          <div class="compare-rank">${i+1}</div>
          <div class="compare-name">${p.name}</div>
          <div class="compare-score">¥${p.price}</div>
        </div>
      `).join('')}
    </div>
  `).join('');
}
</script>
</body>
</html>
