agent-browser eval --stdin <<'EVALEOF'
(async function() {
  const queries = [
    '外卖品类偏好',
    '价格敏感度',
    '购买频次',
    '健康饮食偏好',
    '口味偏好',
    '奶茶偏好',
    '消费能力',
    '用户活跃度'
  ];
  const results = {};
  for (const q of queries) {
    const r = await fetch(`/api/v2/ai/rag/dutvs/assets/searchAll?query=${encodeURIComponent(q)}&assetTypes=label&pageSize=4&idType=1`, {credentials:'include'});
    const d = await r.json();
    results[q] = (d.data||[]).map(l => ({id:l.id, name:l.assetName, space:l.spaceName, sim:(l.similarity*100).toFixed(0)+'%', desc:l.descComment?.substring(0,40)}));
  }
  return JSON.stringify(results, null, 2);
})()
