];

const KEYWORDS = [
  {kw:'汉堡',emoji:'🍔'},{kw:'奶茶',emoji:'🧋'},{kw:'沙拉',emoji:'🥗'},
  {kw:'炸鸡',emoji:'🍗'},{kw:'米饭',emoji:'🍱'},
];

// ============================================================
// 全局状态
// ============================================================
let currentUser = null;
let currentKw = null;
let currentTab = 'search';
const behaviorLog = [];       // 行为日志
const clickedProducts = {};   // { userId -> { productId: count } }
const searchHistory = {};     // { userId -> [kw, ...] }
const stats = { search: 0, click: 0, switch: 0, kw: new Set() };

// ============================================================
// 工具函数
// ============================================================
function now() {
  return new Date().toLocaleTimeString('zh-CN', {hour:'2-digit', minute:'2-digit', second:'2-digit'});
}

function scoreProduct(p, user, behaviorBoost = 0) {
  const w = user.weights;
  let s = 1.0;
  s *= (w.health[p.tags.health] || 1.0);
  s *= (w.price[p.tags.price] || 1.0);
  s *= (w.quality[p.tags.quality] || 1.0);
  s *= (w.taste[p.tags.taste] || 1.0);
  s *= (1 + Math.log10(p.sales + 1) * 0.04);
  s += behaviorBoost;
  return s;
}

function getReason(p, user) {
  const w = user.weights;
  const r = [];
  if ((w.health[p.tags.health]||1) > 2.0) r.push(p.tags.health + '健康');
  if ((w.price[p.tags.price]||1) > 2.0) r.push(p.tags.price + '价');
  if ((w.quality[p.tags.quality]||1) > 2.0) r.push(p.tags.quality);
  if ((w.taste[p.tags.taste]||1) > 2.0) r.push(p.tags.taste + '味');
  return r.slice(0, 2).join('·') || '综合';
}

// ============================================================
// 行为记录
// ============================================================
function addLog(type, user, detail, extra) {
  const entry = { type, user: user.name, detail, extra, time: now() };
  behaviorLog.unshift(entry);

  const typeMap = { search:'搜索', click:'点击', switch:'切换用户' };
  const tagClass = type;
  const tagText = typeMap[type] || type;

  const div = document.createElement('div');
  div.className = `log-entry type-${type}`;
  div.innerHTML = `
    <span class="log-time">${entry.time}</span>
    <span class="log-tag ${tagClass}">${tagText}</span><br>
    <div class="log-detail"><b>${user.avatar} ${user.name}</b> · ${detail}</div>
    ${extra ? `<div style="color:#bbb;font-size:10px;margin-top:2px">${extra}</div>` : ''}
  `;

  const list = document.getElementById('logList');
  if (list.firstChild && list.firstChild.style && !list.firstChild.style) return;
  if (list.innerHTML.includes('操作后此处')) list.innerHTML = '';
  list.insertBefore(div, list.firstChild);

  updateStats();
  updateBehaviorInfer();
}

function updateStats() {
  document.getElementById('statSearch').textContent = stats.search;
  document.getElementById('statClick').textContent = stats.click;
  document.getElementById('statSwitch').textContent = stats.switch;
  document.getElementById('statKw').textContent = stats.kw.size;
}

function updateBehaviorInfer() {
  if (!currentUser) return;
  const uid = currentUser.id;
  const clicks = clickedProducts[uid] || {};
  const searches = searchHistory[uid] || [];

  if (Object.keys(clicks).length === 0 && searches.length === 0) {
    document.getElementById('behaviorInfer').innerHTML = '<span style="color:#ccc">暂无行为数据</span>';
    return;
  }

  // 从点击记录推断偏好
  const clickedList = Object.entries(clicks).sort((a,b)=>b[1]-a[1]).map(([id]) => PRODUCTS.find(p=>p.id===parseInt(id))).filter(Boolean);
  const healthPref = {}, pricePref = {}, tastePref = {};
  clickedList.forEach(p => {
    healthPref[p.tags.health] = (healthPref[p.tags.health]||0) + 1;
    pricePref[p.tags.price] = (pricePref[p.tags.price]||0) + 1;
    tastePref[p.tags.taste] = (tastePref[p.tags.taste]||0) + 1;
  });

  const topHealth = Object.entries(healthPref).sort((a,b)=>b[1]-a[1])[0];
  const topPrice  = Object.entries(pricePref).sort((a,b)=>b[1]-a[1])[0];
  const topTaste  = Object.entries(tastePref).sort((a,b)=>b[1]-a[1])[0];

  const tags = [];
  if (topHealth) tags.push(`偏好${topHealth[0]}健康度商品×${topHealth[1]}`);
  if (topPrice) tags.push(`${topPrice[0]}价区间×${topPrice[1]}`);
  if (topTaste) tags.push(`${topTaste[0]}味偏好×${topTaste[1]}`);
  if (searches.length) tags.push(`搜过: ${[...new Set(searches)].slice(-3).join('/')}`);

  document.getElementById('behaviorInfer').innerHTML =
    `<div class="behavior-tags">${tags.map(t=>`<span class="behavior-tag">${t}</span>`).join('')}</div>`;
}

function clearLog() {
  document.getElementById('logList').innerHTML = '<div style="color:#ccc;font-size:11px;text-align:center;padding:20px">操作后此处记录行为数据</div>';
  stats.search = 0; stats.click = 0; stats.switch = 0; stats.kw = new Set();
  Object.keys(clickedProducts).forEach(k => delete clickedProducts[k]);
  Object.keys(searchHistory).forEach(k => delete searchHistory[k]);
  updateStats();
  document.getElementById('behaviorInfer').innerHTML = '<span style="color:#ccc">暂无行为数据</span>';
  document.getElementById('behaviorReco').innerHTML = '<div style="color:#ccc;font-size:12px;text-align:center;padding:16px">搜索并点击商品后，生成个性化推荐</div>';
}

// ============================================================
// 渲染用户选择器
// ============================================================
function renderUserSelector() {
  document.getElementById('userSelector').innerHTML = USERS.map(u => `
    <button class="user-btn" id="ubtn-${u.id}" onclick="selectUser('${u.id}')">
      <span class="user-btn-avatar">${u.avatar}</span>
