function renderSearchResults(items, kw) {
  document.getElementById('section-initial').style.display = 'none';
  document.getElementById('section-results').style.display = '';
  document.getElementById('result-title').textContent = `"${kw}" 的搜索结果（${items.length}个）`;
  document.getElementById('result-persona-badge').textContent = `${currentUser.emoji} ${currentUser.name}`;

  const list = document.getElementById('search-result-list');
  if (items.length === 0) {
    list.innerHTML = `<div class="result-empty"><div class="icon">🔍</div>没有找到相关商品<br><span style="font-size:10px">换个关键词试试</span></div>`;
    return;
  }

  list.innerHTML = items.map((p, i) => {
    const rankClass = i === 0 ? 'rank-1' : i === 1 ? 'rank-2' : i === 2 ? 'rank-3' : '';
    const rankBadge = i < 3 ? `<div class="rank-badge ${i===1?'r2':i===2?'r3':''}">#${i+1}</div>` : '';
    const tagHtml = p.tags.slice(0,2).map(t => {
      const cls = ['健康','低卡','低脂','素食','全谷物','高蛋白','低糖'].includes(t) ? 'health' :
                  ['超值','超便宜','经济'].includes(t) ? 'cheap' : '';
      return `<span class="product-tag ${cls}">${t}</span>`;
    }).join('');
    return `
      <div class="product-card ${rankClass}" onclick="clickProduct(${p.id},'${p.name}')">
        <div class="product-emoji">${p.emoji}</div>
        <div class="product-body">
          <div class="product-name">${p.name}</div>
          <div class="product-shop">${p.shop}</div>
          <div class="product-tags">${tagHtml}</div>
        </div>
        <div class="product-right">
          <div class="product-price">¥${p.price}</div>
          <div class="product-rating">★ ${(4.0 + p.qualityScore).toFixed(1)}</div>
          ${rankBadge}
        </div>
      </div>`;
  }).join('');
}

// ===================== 首页推荐 =====================
function renderHomeProducts() {
  if (!currentUser) return;
  const allScored = PRODUCTS.map(p => ({ ...p, score: scoreProduct(p, currentUser) }))
