  { id:20, name:'玛格丽特披萨', shop:'意式小馆', emoji:'🍕', price:45, priceLevel:3, healthScore:0.55, qualityScore:0.8, baseScore:0.68, category:'披萨', tags:['经典意式'], searchKeys:['披萨'] },
  { id:21, name:'芝心培根披萨', shop:'必胜客', emoji:'🍕', price:62, priceLevel:3, healthScore:0.3, qualityScore:0.75, baseScore:0.7, category:'披萨', tags:['芝心'], searchKeys:['披萨','培根'] },
  { id:22, name:'素食蔬菜披萨', shop:'素食星球', emoji:'🍕', price:38, priceLevel:2, healthScore:0.8, qualityScore:0.65, baseScore:0.63, category:'披萨', tags:['素食','健康'], searchKeys:['披萨','素食'] },
  { id:23, name:'6寸个人披萨', shop:'快拿', emoji:'🍕', price:18, priceLevel:1, healthScore:0.35, qualityScore:0.45, baseScore:0.71, category:'披萨', tags:['小份','经济'], searchKeys:['披萨'] },
];

// ===================== 状态 =====================
let currentUser = null;
let searchHistory = ['汉堡', '奶茶', '沙拉'];
let currentPage = 'home';
let stats = { search: 0, click: 0, switch: 0, kw: new Set() };
let behaviorClicks = [];

// ===================== 页面导航 =====================
document.getElementById('btn-to-search').addEventListener('click', () => goToSearch());
document.getElementById('btn-back-home').addEventListener('click', () => goToHome());
document.getElementById('btn-search-submit').addEventListener('click', () => doSearch());
document.getElementById('search-input').addEventListener('keydown', (e) => { if (e.key === 'Enter') doSearch(); });
document.getElementById('search-input').addEventListener('input', (e) => {
  if (e.target.value.trim() === '') showInitialState();
});
document.getElementById('btn-clear-history').addEventListener('click', clearHistory);

function goToSearch(prefill) {
  document.getElementById('page-home').classList.add('hidden');
  document.getElementById('page-search').classList.remove('hidden');
  currentPage = 'search';
  showInitialState();
  if (prefill) {
    document.getElementById('search-input').value = prefill;
    setTimeout(() => doSearch(), 50);
  } else {
    setTimeout(() => document.getElementById('search-input').focus(), 100);
  }
}

function goToHome() {
  document.getElementById('page-search').classList.add('hidden');
  document.getElementById('page-home').classList.remove('hidden');
  document.getElementById('search-input').value = '';
  currentPage = 'home';
}

function showInitialState() {
  document.getElementById('section-initial').style.display = '';
  document.getElementById('section-results').style.display = 'none';
  renderHistory();
}

// ===================== 搜索逻辑 =====================
function fillSearch(kw) {
  document.getElementById('search-input').value = kw;
  doSearch();
}

function doSearch() {
  const kw = document.getElementById('search-input').value.trim();
  if (!kw) return;
  if (!currentUser) {
    document.getElementById('search-input').value = '';
    document.getElementById('search-input').placeholder = '请先选择用户画像！';
    setTimeout(() => { document.getElementById('search-input').placeholder = '搜索美食、商家…'; }, 1500);
    return;
  }

  // 更新历史
  if (!searchHistory.includes(kw)) {
    searchHistory.unshift(kw);
    if (searchHistory.length > 8) searchHistory.pop();
  }
  renderHistory();

  // 统计
  stats.search++;
  stats.kw.add(kw);
  document.getElementById('stat-search').textContent = stats.search;
  document.getElementById('stat-kw').textContent = stats.kw.size;

  // 日志
  addLog('search', `${currentUser.emoji} ${currentUser.name} 搜索「${kw}」`);

  // 关键词匹配
  const kwLower = kw.toLowerCase();
  const matched = PRODUCTS.filter(p =>
    p.name.includes(kw) || p.category.includes(kw) ||
    p.searchKeys.some(k => k.includes(kw) || kw.includes(k)) ||
    p.tags.some(t => t.includes(kw))
  );

  // 个性化评分
  const scored = matched.map(p => ({
    ...p,
    score: scoreProduct(p, currentUser)
  })).sort((a, b) => b.score - a.score);

  renderSearchResults(scored, kw);

  // 中栏快速搜索按钮高亮
  document.querySelectorAll('.kw-btn').forEach(btn => {
    btn.classList.toggle('active', btn.textContent.includes(kw));
  });

  // 跨用户对比
  updateComparison(kw, matched);
}

function scoreProduct(product, user) {
  let score = product.baseScore;
  score += product.healthScore * user.healthWeight * 0.3;
  score -= (product.priceLevel - 1) * user.priceWeight * 0.25;
  score += product.qualityScore * user.qualityWeight * 0.2;
  score += (user.categoryBonus[product.category] || 0);
  score += (Math.random() - 0.5) * 0.08; // 小扰动
  return Math.max(0, Math.min(1, score));
}

function renderSearchResults(items, kw) {
  document.getElementById('section-initial').style.display = 'none';
  document.getElementById('section-results').style.display = '';
  document.getElementById('result-title').textContent = `"${kw}" 的搜索结果（${items.length}个）`;
  document.getElementById('result-persona-badge').textContent = `${currentUser.emoji} ${currentUser.name}`;

  const list = document.getElementById('search-result-list');
  if (items.length === 0) {
    list.innerHTML = `<div class="result-empty"><div class="icon">🔍</div>没有找到相关商品<br><span style="font-size:10px">换个关键词试试</span></div>`;
    return;
  }

  list.innerHTML = items.map((p, i) => {
    const rankClass = i === 0 ? 'rank-1' : i === 1 ? 'rank-2' : i === 2 ? 'rank-3' : '';
    const rankBadge = i < 3 ? `<div class="rank-badge ${i===1?'r2':i===2?'r3':''}">#${i+1}</div>` : '';
    const tagHtml = p.tags.slice(0,2).map(t => {
      const cls = ['健康','低卡','低脂','素食','全谷物','高蛋白','低糖'].includes(t) ? 'health' :
                  ['超值','超便宜','经济'].includes(t) ? 'cheap' : '';
      return `<span class="product-tag ${cls}">${t}</span>`;
    }).join('');
    return `
      <div class="product-card ${rankClass}" onclick="clickProduct(${p.id},'${p.name}')">
        <div class="product-img-wrap">${p.emoji}</div>
        <div class="product-body">
          <div class="product-name">${p.name}</div>
          <div class="product-shop">${p.shop}</div>
          <div class="product-tags">${tagHtml}</div>
        </div>
        <div class="product-right">
          <div class="product-price"><span class="product-price-unit">¥</span>${p.price}</div>
          <div class="product-rating">★ ${(4.0 + p.qualityScore).toFixed(1)}</div>
          ${rankBadge}
        </div>
      </div>`;
  }).join('');
}

// ===================== 首页推荐 =====================
function renderHomeProducts() {
  if (!currentUser) return;
  const allScored = PRODUCTS.map(p => ({ ...p, score: scoreProduct(p, currentUser) }))
    .sort((a, b) => b.score - a.score).slice(0, 8);

  document.getElementById('home-reco-title').textContent = `${currentUser.emoji} 为${currentUser.name}推荐`;
  document.getElementById('home-user-label').textContent = `${currentUser.emoji} ${currentUser.name}`;
  document.getElementById('search-trigger-text').textContent = '搜索美食…';
  document.getElementById('search-trigger-hot').textContent = allScored[0].category;

  const list = document.getElementById('home-product-list');
  list.innerHTML = allScored.map((p, i) => {
    const rankClass = i === 0 ? 'rank-1' : i === 1 ? 'rank-2' : i === 2 ? 'rank-3' : '';
    const rankBadge = i < 3 ? `<div class="rank-badge ${i===1?'r2':i===2?'r3':''}">#${i+1}</div>` : '';
    const tagHtml = p.tags.slice(0,1).map(t => {
      const cls = ['健康','低卡','低脂','素食','全谷物','高蛋白'].includes(t) ? 'health' :
                  ['超值','超便宜','经济'].includes(t) ? 'cheap' : '';
      return `<span class="product-tag ${cls}">${t}</span>`;
    }).join('');
    return `
      <div class="product-card ${rankClass}" onclick="clickProduct(${p.id},'${p.name}')">
        <div class="product-img-wrap">${p.emoji}</div>
        <div class="product-body">
          <div class="product-name">${p.name}</div>
          <div class="product-shop">${p.shop}</div>
          <div class="product-tags">${tagHtml}</div>
        </div>
        <div class="product-right">
          <div class="product-price"><span class="product-price-unit">¥</span>${p.price}</div>
          ${rankBadge}
        </div>
      </div>`;
  }).join('');
}

// ===================== 用户选择 =====================
function selectUser(uid, silent) {
  currentUser = USERS[uid];
  // 中栏按钮高亮
  document.querySelectorAll('.user-btn').forEach(b => b.classList.toggle('active', b.dataset.user === uid));
  // 首页头像条高亮
  document.querySelectorAll('.user-avatar-btn').forEach(b => b.classList.toggle('active', b.dataset.uid === uid));
  // 更新首页右上角用户名
  document.getElementById('home-user-label').textContent = `${currentUser.emoji} ${currentUser.name}`;
  if (!silent) {
    stats.switch++;
    document.getElementById('stat-switch').textContent = stats.switch;
    addLog('switch', `切换到 ${currentUser.emoji} ${currentUser.name}（${currentUser.desc}）`);
  }
  renderWeights();
  renderHomeProducts();
  loadPersonaLabels();
  if (currentPage === 'search') showInitialState();
}

// ===================== 权重渲染 =====================
function renderWeights() {
  const u = currentUser;
  const bars = [
    { label:'价格敏感', val: u.priceWeight, color:'#ff9500' },
    { label:'健康偏好', val: u.healthWeight, color:'#2db47d' },
    { label:'品质偏好', val: u.qualityWeight, color:'#4a6cf7' },
  ];
  document.getElementById('weight-bars').innerHTML = bars.map(b => `
    <div class="weight-row">
      <span class="weight-label">${b.label}</span>
      <div class="weight-bar-wrap"><div class="weight-bar" style="width:${b.val*100}%;background:${b.color}"></div></div>
      <span class="weight-val">${(b.val*10).toFixed(0)}/10</span>
    </div>`).join('');
}

// ===================== Persona API =====================
async function loadPersonaLabels() {
  const u = currentUser;
  const container = document.getElementById('profile-labels');
  container.innerHTML = `<div style="grid-column:1/-1;text-align:center;color:#bbb;font-size:11px;padding:12px">⏳ 正在从 Persona 加载真实标签…</div>`;
  const colors = ['c1','c2','c3','c4'];
  const results = [];
  for (const query of u.labelQueries) {
    try {
      const res = await fetch(`https://persona.sankuai.com/api/v2/ai/rag/dutvs/assets/searchAll?query=${encodeURIComponent(query)}&assetTypes=label&idType=1`);
      const json = await res.json();
      const items = json?.data?.results || [];
      results.push({ query, items: items.slice(0, 3) });
    } catch(e) {
      results.push({ query, items: [], err: true });
    }
  }
  const hasData = results.some(r => r.items.length > 0);
  if (!hasData) {
    container.innerHTML = `<div style="grid-column:1/-1;text-align:center;color:#ccc;font-size:11px;padding:12px">⚠️ 需登录 persona.sankuai.com 后刷新</div>`;
    return;
  }
  container.innerHTML = results.map((r, i) => `
    <div>
      <div class="label-dim-title">${r.query}</div>
      <div class="labels">
        ${r.items.length === 0
          ? `<span style="font-size:10px;color:#ccc">无结果</span>`
          : r.items.map(it => `<span class="label ${colors[i%4]}" title="${it.labelDesc||''}">${it.labelName||it.labelId}</span>`).join('')
        }
      </div>
    </div>`).join('');
}

// ===================== 历史搜索 =====================
function renderHistory() {
  const container = document.getElementById('history-tags');
  const section = document.getElementById('history-section');
  if (searchHistory.length === 0) {
    section.style.display = 'none';
    return;
  }
  section.style.display = '';
  container.innerHTML = searchHistory.map(h =>
    `<span class="history-tag" onclick="fillSearch('${h}')">${h}</span>`
  ).join('');
}

function clearHistory() {
  searchHistory = [];
  renderHistory();
}

// ===================== 快速搜索（中栏） =====================
function quickSearch(kw) {
  if (!currentUser) { alert('请先选择用户！'); return; }
  goToSearch(kw);
}

// ===================== 点击商品 =====================
function clickProduct(id, name) {
  stats.click++;
  document.getElementById('stat-click').textContent = stats.click;
  const p = PRODUCTS.find(x => x.id === id);
  behaviorClicks.push({ category: p.category, priceLevel: p.priceLevel });
  addLog('click', `点击商品「${name}」（${p.category} / ¥${p.price}）`);
  updateBehaviorTags();
}

function updateBehaviorTags() {
  if (behaviorClicks.length === 0) return;
  const catCount = {};
  let cheapClicks = 0;
  behaviorClicks.forEach(c => {
    catCount[c.category] = (catCount[c.category] || 0) + 1;
    if (c.priceLevel === 1) cheapClicks++;
  });
  const topCats = Object.entries(catCount).sort((a,b)=>b[1]-a[1]).slice(0,3);
  const tags = topCats.map(([cat, n]) => `偏好${cat}(${n}次)`);
  if (cheapClicks >= 2) tags.push('价格敏感');
  const wrap = document.getElementById('behavior-tags-wrap');
  wrap.innerHTML = `<div class="behavior-tags">${tags.map(t => `<span class="behavior-tag">${t}</span>`).join('')}</div>`;
}

// ===================== 跨用户对比 =====================
function updateComparison(kw, matched) {
  const panel = document.getElementById('comparison-panel');
  const body = document.getElementById('comparison-body');
  panel.style.display = '';
  const allUsers = Object.entries(USERS);
  const rows = allUsers.map(([uid, u]) => {
    const top = matched.map(p => ({ ...p, score: scoreProduct(p, u) }))
      .sort((a,b) => b.score - a.score).slice(0,2);
    return `<div style="margin-bottom:6px">
      <span style="font-weight:600;font-size:11px">${u.emoji} ${u.name}：</span>
      ${top.map((p,i) => `<span style="font-size:10px;color:${i===0?'#ff6034':'#888'}">${p.name}(¥${p.price})</span>`).join(' › ')}
    </div>`;
  }).join('');
  body.innerHTML = `<div style="font-size:11px;color:#666;margin-bottom:6px">「${kw}」的排序差异：</div>` + rows;
}

// ===================== 日志 =====================
function addLog(type, msg) {
  const list = document.getElementById('log-list');
  const time = new Date().toLocaleTimeString('zh-CN', { hour12: false });
  const placeholder = list.querySelector('div[style]');
  if (placeholder) placeholder.remove();
  const el = document.createElement('div');
  el.className = `log-entry type-${type}`;
  el.innerHTML = `<div class="log-time">${time}</div><div class="log-detail">${msg}</div>`;
  list.insertBefore(el, list.firstChild);
}

function clearLog() {
  document.getElementById('log-list').innerHTML = '<div style="text-align:center;padding:20px;color:#ccc;font-size:12px">操作后此处记录行为数据</div>';
}

// 初始化：默认选中小美
renderHistory();
selectUser('xiaomei', true);
